messages.content:
这个错误是因为 **Qwen2.5-VL 模型在使用 KV Cache 时对多模态输入的 attention_mask 处理有特殊要求**。问题出在：

1. `attention_mask` 的长度与 `input_ids` 不匹配
2. Qwen2.5-VL 的 `prepare_inputs_for_generation` 需要完整的 attention_mask

## 修复方案

```python
def generate_inner_transformers_tools_use_kvcache(self, message, dataset=None):
    print("generate_inner_transformers_tools_use_kvcache")

    if listinstr(['omni'], self.model_path.lower()):
        try:
            from qwen_omni_utils import process_mm_info
        except Exception as err:
            logging.critical("qwen_omni_utils not found")
            raise err
    else:
        try:
            from .vision_process_qwen3vl import process_vision_info
        except Exception as err:
            logging.critical("qwen_vl_utils not found")
            raise err

    # 提取 raw_video 和 question_type
    raw_video = None
    question_type = None

    indices_to_remove = []
    for i, item in enumerate(message):
        if isinstance(item, dict):
            if item.get('type') == 'raw_video' and raw_video is None:
                raw_video = dict(type='raw_video', value=item['value'])
                indices_to_remove.append(i)
            elif item.get('type') == 'question_type' and question_type is None:
                question_type = item.get('value')
                indices_to_remove.append(i)

    for i in sorted(indices_to_remove, reverse=True):
        message.pop(i)

    # 设置 system_prompt
    system_prompt_to_use = self.system_prompt
    if question_type == 'oe':
        system_prompt_to_use = SYSTEM_PROMPT_MULTI_ROUND_OPEN_ENDED
    elif question_type == 'tg':
        system_prompt_to_use = SYSTEM_PROMPT_TG
    elif question_type == 'tg_cgbench':
        system_prompt_to_use = SYSTEM_PROMPT_TG_CGBench

    # 初始化 messages
    messages = []
    if system_prompt_to_use is not None:
        messages.append({'role': 'system', 'content': system_prompt_to_use})

    messages.append({'role': 'user', 'content': self._prepare_content(message, dataset=dataset)})

    # ===== 关键修复：不使用增量 KV Cache，而是使用完整输入 =====
    # Qwen2.5-VL 的多模态 KV Cache 实现有问题，需要特殊处理
    past_key_values = None
    accumulated_images = []
    accumulated_videos = []

    turn_count = 0

    # 第一轮：处理初始视频
    initial_images, initial_videos = process_vision_info([messages])
    if initial_images:
        accumulated_images.extend(initial_images)
    if initial_videos:
        accumulated_videos.extend(initial_videos)

    force_answer = False

    while True:
        torch.cuda.empty_cache()

        if self.verbose:
            print(f"(Round {turn_count}) Messages: \n{messages}")
            print(f"Accumulated videos: {len(accumulated_videos)}, images: {len(accumulated_images)}")
            print("-"*40)

        # ===== 修复1: 始终使用完整输入（不做增量切片）=====
        text = self.processor.apply_chat_template(
            [messages], 
            tokenize=False, 
            add_generation_prompt=True,
            chat_template=CHAT_TEMPLATE
        )

        inputs = self.processor(
            text=text, 
            images=accumulated_images if accumulated_images else None, 
            videos=accumulated_videos if accumulated_videos else None, 
            padding=True, 
            return_tensors='pt'
        )
        inputs = inputs.to('cuda')

        if listinstr(['omni'], self.model_path.lower()):
            self.generate_kwargs['use_audio_in_video'] = self.use_audio_in_video
            self.generate_kwargs['return_audio'] = False

        stop_criteria = StoppingCriteriaList([
            KeywordsStoppingCriteria(
                keywords=["</grounding>", "</answer>"],
                tokenizer=self.processor.tokenizer,
                input_ids=inputs.input_ids,
            )
        ])

        # ===== 修复2: 使用完整输入 + past_key_values =====
        generate_kwargs_with_cache = {
            **self.generate_kwargs,
            'do_sample': self.do_sample,
            'use_cache': True,
            'return_dict_in_generate': True,
        }

        # ===== 关键修复：检查是否可以使用缓存 =====
        use_past_kv = False
        if past_key_values is not None and turn_count > 0:
            try:
                # 获取缓存长度
                cache_length = past_key_values[0][0].shape[2]
                current_input_length = inputs.input_ids.shape[1]

                if self.verbose:
                    print(f"📊 Cache length: {cache_length}, Current input: {current_input_length}")

                # ===== 核心修复：只在没有新视觉输入时使用缓存 =====
                # Qwen2.5-VL 在添加新视觉 token 时会导致 attention_mask 错位
                # 所以我们采取保守策略：只有纯文本追加时才使用缓存

                # 检查是否只是文本追加（没有新的视觉输入）
                if current_input_length > cache_length:
                    # 有新的 token，检查是否有新的视觉输入
                    prev_video_count = len(accumulated_videos) - (1 if turn_count > 0 else 0)

                    # 如果这一轮没有添加新视频，可以尝试使用缓存
                    if turn_count > 0 and len(accumulated_videos) == prev_video_count:
                        use_past_kv = True
                        if self.verbose:
                            print("✅ Using KV cache (text-only append)")
                    else:
                        if self.verbose:
                            print("⚠️ New vision input detected, not using cache")
                elif current_input_length <= cache_length:
                    # 输入长度没有增加或减少，不使用缓存
                    if self.verbose:
                        print(f"⚠️ Input length anomaly, resetting cache")
            except Exception as e:
                logging.warning(f"Cache check failed: {e}, resetting cache")
                past_key_values = None

        # ===== 修复3: 只在安全情况下传递 past_key_values =====
        if use_past_kv:
            generate_kwargs_with_cache['past_key_values'] = past_key_values
        else:
            # 不使用缓存时，确保不传递 past_key_values
            past_key_values = None

        if not force_answer:
            generate_kwargs_with_cache['stopping_criteria'] = stop_criteria

        # ===== 执行生成 =====
        try:
            outputs = self.model.generate(**inputs, **generate_kwargs_with_cache)

            # ===== 修复4: 只在成功使用缓存时更新 =====
            if use_past_kv or past_key_values is None:
                past_key_values = outputs.past_key_values
                if self.verbose and past_key_values is not None:
                    new_cache_length = past_key_values[0][0].shape[2]
                    print(f"✅ Updated cache length: {new_cache_length}")

        except Exception as e:
            logging.error(f"Generation failed: {e}")

            # 如果生成失败，重置缓存并重试
            if past_key_values is not None or use_past_kv:
                logging.warning("Retrying without cache...")
                past_key_values = None
                generate_kwargs_with_cache = {
                    **self.generate_kwargs,
                    'do_sample': self.do_sample,
                    'use_cache': True,
                    'return_dict_in_generate': True,
                }
                if not force_answer:
                    generate_kwargs_with_cache['stopping_criteria'] = stop_criteria

                try:
                    outputs = self.model.generate(**inputs, **generate_kwargs_with_cache)
                    past_key_values = outputs.past_key_values
                except Exception as e2:
                    logging.error(f"Retry also failed: {e2}")
                    raise e2
            else:
                raise e

        # 提取生成的 token
        generated_ids = outputs.sequences
        input_length = inputs.input_ids.shape[1]

        generated_ids
